class RateLimiter:
    def __init__(self, window=RATE_LIMIT_WINDOW, max_requests=RATE_LIMIT_MAX):
        self.window = window
        self.max_requests = max_requests
        self.requests = {}
        self._lock = threading.Lock()

    def is_allowed(self, ip):
        now = time.time()
        with self._lock:
            if ip not in self.requests:
                self.requests[ip] = []

            # Clean old entries
            self.requests[ip] = [t for t in self.requests[ip] if now - t < self.window]

            if len(self.requests[ip]) >= self.max_requests:
                return False

            self.requests[ip].append(now)
            return True

    def cleanup(self):
        now = time.time()
        with self._lock:
            expired = [ip for ip, times in self.requests.items()
                       if all(now - t >= self.window for t in times)]
            for ip in expired:
                del self.requests[ip]


class ChallengeManager:
    """Implements challenge-response to prevent IP spoofing for expensive queries."""

    def __init__(self, timeout=CHALLENGE_TIMEOUT):
        self.challenges = {}
        self.timeout = timeout
        self._lock = threading.Lock()

    def generate_challenge(self, addr):
        challenge = random.randint(1, 2**31 - 1)
        with self._lock:
            self.challenges[addr] = (challenge, time.time())
        return challenge

    def verify_challenge(self, addr, challenge):
        with self._lock:
            if addr not in self.challenges:
                return False
            stored_challenge, timestamp = self.challenges[addr]
            if time.time() - timestamp > self.timeout:
                del self.challenges[addr]
                return False
            if stored_challenge == challenge:
                del self.challenges[addr]
                return True
            return False

    def cleanup(self):
        now = time.time()
        with self._lock:
            expired = [addr for addr, (_, ts) in self.challenges.items()
                       if now - ts > self.timeout]
            for addr in expired:
                del self.challenges[addr]


# Protocol constants
QUERY_HEADER = b'\xFF\xFF\xFF\xFF'

# Query types
QUERY_INFO = 0x01          # Basic server info
QUERY_PLAYERS = 0x02       # Player list
QUERY_FULL_STATUS = 0x03   # Full status (info + players + rules)
QUERY_RULES = 0x04         # Server rules/settings
QUERY_PING = 0x05          # Simple ping
QUERY_CHALLENGE = 0x06     # Request a challenge number

# Response types
RESP_INFO = 0x11
RESP_PLAYERS = 0x12
RESP_FULL_STATUS = 0x13
RESP_RULES = 0x14
RESP_PONG = 0x15
RESP_CHALLENGE = 0x16
RESP_FRAGMENT = 0x17
RESP_ERROR = 0xFF


