    def _build_packet(self, response_type, payload):
        """Build a response packet with header and type."""
        return QUERY_HEADER + struct.pack("B", response_type) + payload

    def _fragment_response(self, response_type, data, request_id=0):
        """Fragment large responses into multiple UDP packets."""
        fragments = []
        total_fragments = (len(data) + FRAGMENT_SIZE - 1) // FRAGMENT_SIZE

        for i in range(total_fragments):
            offset = i * FRAGMENT_SIZE
            chunk = data[offset:offset + FRAGMENT_SIZE]

            # Fragment header: request_id (4) + fragment_num (2) + total_fragments (2) + original_type (1)
            frag_header = struct.pack("<IHHBx", request_id, i, total_fragments, response_type)
            packet = QUERY_HEADER + struct.pack("B", RESP_FRAGMENT) + frag_header + chunk
            fragments.append(packet)

        return fragments

    def _send_response(self, data, response_type, addr, request_id=0):
        """Send response, fragmenting if necessary."""
        packet = self._build_packet(response_type, data)

        if len(packet) <= FRAGMENT_SIZE:
            self.sock.sendto(packet, addr)
            with self._stats_lock:
                self.stats["bytes_sent"] += len(packet)
        else:
            # Need to fragment
            fragments = self._fragment_response(response_type, data, request_id)
            for fragment in fragments:
                self.sock.sendto(fragment, addr)
                with self._stats_lock:
                    self.stats["bytes_sent"] += len(fragment)
                    self.stats["fragments_sent"] += 1
            logger.info(f"Sent {len(fragments)} fragments to {addr} for response type 0x{response_type:02X}")

